fn validate_fhe_call_payload(input: &[u8], max_ttl: u64) -> Result<(), PayloadValidationError> {
    validate_executor_request_payload(input, max_ttl)?;
    let data = try_decode_precompile_data(FHE_PRECOMPILE, input)?;
    if crate::long_running::validate_fhe_payload_structure(input).is_ok() {
        let max_proof_block = u64_static_head_field(input, 10, "max_proof_block")?;
        validate_phase2_deadline_offset(max_proof_block, data.ttl)?;
    }
    Ok(())
}

